class Stack:
 def __init__(self, max_size):
 self.max_size = max_size
 self.array = [None] * max_size
 self.top = -1

 def push(self, value):
 if self.top == self.max_size - 1:
 raise OverflowError('Stack is full')
 self.top += 1
 self.array[self.top] = value

 def pop(self):
 if self.top == -1:
 raise UnderflowError('Stack is empty')
 value = self.array[self.top]
 self.top -= 1
 return value

 def peek(self):
 if self.top == -1:
 raise UnderflowError('Stack is empty')
 return self.array[self.top]

 def is_empty(self):
 return self.top == -1

#include <stdio.h>

#define MAX 100

int stack[MAX];
int top = -1;

void push(int value) {
 if (top == MAX - 1) {
 printf('Stack is full');
 return;
 }
 stack[++top] = value;
}

int pop() {
 if (top == -1) {
 printf('Stack is empty');
 return -1;
 }
 return stack[top--];
}

int peek() {
 if (top == -1) {
 printf('Stack is empty');
 return -1;
 }
 return stack[top];
}

int is_empty() {
 return top == -1;
}
